import{_ as o,o as a,c as s,an as r}from"./chunks/framework.ORD7L0X6.js";const u=JSON.parse('{"title":"Release notes","description":"","frontmatter":{},"headers":[],"relativePath":"release-notes.md","filePath":"release-notes.md","lastUpdated":null}'),t={name:"release-notes.md"};function c(i,e,l,d,n,p){return a(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="Release-notes" tabindex="-1">Release notes <a class="header-anchor" href="#Release-notes" aria-label="Permalink to &quot;Release notes {#Release-notes}&quot;">​</a></h1><p>ScoringRules.jl follows a hybrid changelog approach:</p><ul><li><p><strong>GitHub Releases</strong>: All releases (automatically generated by TagBot)</p></li><li><p><strong>NEWS.md</strong>: Major releases requiring detailed context (shown below)</p></li></ul><p>See <a href="https://github.com/EpiAware/ScoringRules.jl/releases" target="_blank" rel="noreferrer">GitHub Releases</a> for minor/patch release information.</p><h2 id="Unreleased" tabindex="-1">Unreleased <a class="header-anchor" href="#Unreleased" aria-label="Permalink to &quot;Unreleased {#Unreleased}&quot;">​</a></h2><p>First working version: a port of the R <a href="https://github.com/FK83/scoringRules" target="_blank" rel="noreferrer"><code>scoringRules</code></a> package (Jordan, Krüger, Lerch and Allen). See the README for attribution and provenance.</p><ul><li><p>Three univariate scores via multiple dispatch: <code>crps</code>, <code>logs</code>, <code>dss</code>. <code>logs</code> and <code>dss</code> work for any <code>Distributions.jl</code> univariate type; <code>crps</code> has a closed form for each supported family and a quadrature fallback otherwise.</p></li><li><p>Closed-form CRPS for the normal (plus truncated, censored and generalised truncated/censored), logistic, Student-t, Laplace, exponential, gamma, beta, uniform, log-normal, log-logistic, log-Laplace, GEV, GPD, two-piece normal, two-piece exponential and mixture-of-normals families, and for the Poisson, negative binomial, binomial and hypergeometric discrete families.</p></li><li><p><code>LogLaplace</code>, <code>TwoPieceNormal</code> and <code>TwoPieceExponential</code> distribution types (the log-logistic uses <code>Distributions.LogLogistic</code>).</p></li><li><p>Sample/ensemble forecasts: <code>crps</code> (empirical and kernel-density), <code>logs</code>, <code>dss</code> on vectors; the energy score <code>es</code>, variogram score <code>vs</code> and maximum-mean-discrepancy score <code>mmds</code> on multivariate ensembles.</p></li><li><p>Threshold- and outcome-weighted scores (<code>twcrps</code>, <code>owcrps</code>, <code>twes</code>, <code>owes</code>, <code>twvs</code>, <code>owvs</code>, <code>twmmds</code>, <code>owmmds</code>).</p></li><li><p>Quantile and interval scores (<code>quantile_score</code>, <code>interval_score</code>), the ranked probability score <code>rps</code>, and the moment-based <code>dss_moments</code>.</p></li><li><p>Every scoring function is checked against R <code>scoringRules</code> 1.1.3 in the test suite.</p></li></ul><p>This file tracks notes for major releases and significant milestones; GitHub Releases (auto-generated from merged PRs) cover every release in between.</p>',8)])])}const g=o(t,[["render",c]]);export{u as __pageData,g as default};
